import type Color from "../../../Color.js";
import type { JSONSupport } from "../../../core/JSONSupport.js";
import type { ColorLike } from "../../../Color.js";

export interface ColorStopProperties extends Partial<Pick<ColorStop, "label" | "value">> {
  /** The [Color](https://developers.arcgis.com/javascript/latest/references/core/Color/) used to render features with the given [value](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/support/ColorStop/#value). */
  color?: ColorLike;
}

/**
 * Defines a color stop used for creating a continuous color visualization in a
 * [color visual variable](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/ColorVariable/#stops).
 *
 * @since 4.10
 * @see [ColorVariable](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/ColorVariable/)
 * @see [Guide - Esri color ramps](https://developers.arcgis.com/javascript/latest/esri-color-ramps/)
 * @see [Guide - Visualization best practices](https://developers.arcgis.com/javascript/latest/visualization-best-practices/)
 */
export default class ColorStop extends JSONSupport {
  constructor(properties?: ColorStopProperties);
  /** The [Color](https://developers.arcgis.com/javascript/latest/references/core/Color/) used to render features with the given [value](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/support/ColorStop/#value). */
  get color(): Color;
  set color(value: ColorLike);
  /** A string value used to label the stop along the color ramp in the [Legend](https://developers.arcgis.com/javascript/latest/references/map-components/components/arcgis-legend/). */
  accessor label: string | null | undefined;
  /** Specifies the data value to map to the given [color](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/support/ColorStop/#color). */
  accessor value: number;
  /**
   * Creates a deep clone of the ColorStop.
   *
   * @returns A deep clone of the color
   *   stop that invoked this method.
   * @example
   * // Creates a deep clone of the visual variable
   * const stops = renderer.visualVariables[0].stops.map(function(stop){
   *   return stop.clone();
   * });
   */
  clone(): ColorStop;
}